// // This module implements a 9-bit parallel loadable shift register. It loads data from the input bus (data_in) when the load signal (load) is low, and shifts the data to the left on every negative edge of the clock signal when the shift signal (shift) is low. The register resets to 11111111 when the reset signal (reset) is inactive.
module loadable_shift_register_8bit 
(
  input reset,
  input clk,
  input load,
  input shift,
  input [7:0] data_in,

  output reg [7:0] q
);

  always @(posedge clk or posedge reset) begin
    if (reset) 
	begin
      q <= 8'b00000000;
    end 

	else if (load) 
	begin
      q <= data_in;
    end 

	else if (shift) 
	begin
      q <= {1'b0, q[7:1]};
    end
  end

endmodule
